import  {useState, useEffect} from 'react';
import { useParams } from 'react-router-dom';


const Details = () =>{
    let{userid} = useParams();
    // it use to capture value from browser url in react
    let[title, pickTitle] = useState("");
    let[content, pickcontent] = useState("");
    let[date, pickdate] = useState("");
   

    const getuserinfo = () =>{
        let url = "http://localhost:4444/note/"+userid;
        fetch(url)
        .then(response => response.json())
        .then(empinfo =>{
            pickTitle(empinfo.title);
            pickcontent(empinfo.content);
            pickdate(empinfo.date);
        })
    }

     useEffect(() =>{
        getuserinfo();
     },[1]);

    const back = () =>{
        window.location.href = "#/";
       };
     
       

   return(
     <div className="container mt-4">
        <div className="row">
            <div className="col-lg-3"> </div>
            <div className="col-lg-6 text-center border bg-light text-dark p-5 rounded mt-5"> 
              <h1 className=" text-primary mb-3"> Note details </h1>

               <table className=' table '>
                   <thead>
                    <tr>
                    <th>Title:</th>
                    <td colSpan={2}><input type="text" className="form-control" onChange={obj => pickTitle(obj.target.value)} value={title} disab/> </td>
                    </tr>

                    <tr>
                    <th>Content :</th>
                    <td colSpan={2}><textarea className="form-control" onChange={obj=> pickcontent(obj.target.value)} value={content}></textarea> </td>
                    </tr>

                    <tr>
                    <th> Last modified :</th>
                    <td colSpan={2}>{date} </td>
                    </tr>

                    <tr>
                    <td colSpan={3}><button className="btn btn-danger" onClick={back}> Back </button></td>
                    </tr>
                   </thead>
               </table>
             </div> 

             <div className="col-lg-3"> </div>
             </div> 
        </div>  
   )
}


export default Details;
